var checkClass=function(){if($(".page-section").hasClass("hide")){$(".page-section").removeClass("hide")}};if($(".promos_activas_click").hasClass("active")){checkClass();$(".page-section:not(.promos_activas)").toggleClass("hide")}$(".all").click(function(){checkClass();var element=document.getElementById("sinpromos");element.style.display="none"});$(".promos_activas_click").click(function(){checkClass();$(".page-section:not(.promos_activas)").toggleClass("hide")});$(".promos_finalizadas_click").click(function(){checkClass();$(".page-section:not(.promos_finalizadas)").toggleClass("hide");var element=document.getElementById("sinpromos");element.style.display="none"});if($("#datatable_ganadores").length>0){$("#datatable_ganadores").DataTable({paging:true,ordering:false,info:false,language:{lengthMenu:"visualización -- registros por página",zeroRecords:"No hay datos de su elección.",infoEmpty:"No hay registros disponibles"},layout:{topStart:"info",topEnd:{search:{placeholder:"Últimos 5 dígitos de CI"}}}})}const elemento=$(".dt-layout-start:first");const campoTexto=$('<div class="title_table_winners">Ellos ya ganaron usando Yape</div>');elemento.append(campoTexto);$(".button").click(function(){if($(".page-section").children(":visible").length==0){var element=document.getElementById("sinpromos");element.style.display="block";document.getElementsByClassName("conpromos")[0].style.display="none"}$(".button").removeClass("active");$(this).addClass("active");document.getElementsByClassName("conpromos")[0].style.display="block"});